9	const SURVIVAL_MIN_NEIGHBORS = 2;
10	const SURVIVAL_MAX_NEIGHBORS = 3;
11	const SURVIVAL_NEIGHBOR_COUNTS: ReadonlyArray<number> = [
12	  SURVIVAL_MIN_NEIGHBORS,
13	  SURVIVAL_MAX_NEIGHBORS,
14	];
