18	export function nextGeneration(cells: Cell[]): Cell[] {
19	  const liveCells = new Set(cells.map(cellKey));
20	  const isAlive = (cell: Cell): boolean => liveCells.has(cellKey(cell));
21	  const countLiveNeighbors = (cell: Cell): number =>
22	    neighborsOf(cell).filter(isAlive).length;
23	  const survivesOrIsBorn = (cell: Cell): boolean => {
24	    const liveNeighbors = countLiveNeighbors(cell);
25	    return isAlive(cell)
26	      ? SURVIVAL_NEIGHBOR_COUNTS.includes(liveNeighbors)
27	      : liveNeighbors === REPRODUCTION_NEIGHBORS;
28	  };
29	  return candidateCells(cells).filter(survivesOrIsBorn);
30	}
31	
32	function cellKey([x, y]: Cell): string {
33	  return `${x},${y}`;
34	}
35	
36	function neighborsOf([x, y]: Cell): Cell[] {
37	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
38	}
39	
40	function candidateCells(liveCells: Cell[]): Cell[] {
41	  const candidates = new Map<string, Cell>();
42	  for (const cell of liveCells) {
43	    candidates.set(cellKey(cell), cell);
44	    for (const neighbor of neighborsOf(cell)) {
45	      candidates.set(cellKey(neighbor), neighbor);
46	    }
47	  }
48	  return [...candidates.values()];
49	}
