1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input — []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with 0 neighbors (Rule 1: Underpopulation) — [(0,0)] becomes []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each with 1 neighbor (Rule 1: Underpopulation) — [(0,1),(1,1)] becomes []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with 2 neighbors (Rule 2: Survival) — center of L-shape survives", () => {
15	    // L-shape: (0,2) has neighbors (0,1) and (1,2) → 2 live neighbors → survives
16	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
17	    expect(result).toContainEqual([0, 2]);
18	  });
19	  it("should keep a live cell alive with 3 neighbors (Rule 2: Survival) — center of T-shape survives", () => {
20	    // T-shape: (1,2) has neighbors (0,2),(2,2),(1,1) → 3 live neighbors → survives
21	    const result = nextGeneration([[0, 2], [1, 2], [2, 2], [1, 1]]);
22	    expect(result).toContainEqual([1, 2]);
23	  });
24	  it("should kill a live cell with 4 neighbors (Rule 3: Overpopulation) — center of plus dies", () => {
25	    // Plus shape: (1,1) has 4 neighbors at (0,1),(2,1),(1,0),(1,2) → dies
26	    const result = nextGeneration([[0, 1], [2, 1], [1, 0], [1, 2], [1, 1]]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("should revive a dead cell with exactly 3 live neighbors (Rule 4: Reproduction) — (1,1) becomes alive in L-shape", () => {
30	    // L-shape from spec: dead (1,1) has neighbors (0,1),(0,2),(1,2) → 3 → reborn
31	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("should oscillate a vertical blinker to horizontal — [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]", () => {
35	    const sortCells = (cs: [number, number][]) =>
36	      [...cs].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
37	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
38	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
39	  });
40	  it("should keep a block stable (still life) — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
41	    const sortCells = (cs: [number, number][]) =>
42	      [...cs].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
43	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
44	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
45	  });
46	  it.todo("should handle negative coordinates — blinker at negative positions oscillates correctly");
47	});
